/* script.js — Canvas particles + Mobile card interaction + Image inject */

/* ══════════════════════════════════════════
   1. IMAGE DATA  (base64 injected at build)
══════════════════════════════════════════ */
const IMAGES = {
  photo: "data:image/png;base64,",
  music: "data:image/png;base64,",
  kmitl: "data:image/png;base64,",
  curriculum: "data:image/png;base64,",
  school: "data:image/png;base64,",
};


/* ══════════════════════════════════════════
   2. INJECT IMAGES — one base64 per key
══════════════════════════════════════════ */
(function injectImages() {
  if (typeof IMAGES === 'undefined') return;
  document.querySelectorAll('[data-img]').forEach(el => {
    const key = el.getAttribute('data-img');
    if (IMAGES[key]) el.src = IMAGES[key];
  });
})();

/* ══════════════════════════════════════════
   3. ANIMATED BACKGROUND CANVAS
══════════════════════════════════════════ */
(function initCanvas() {
  const canvas = document.getElementById('bgCanvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');

  const COLORS = ['#FFCBA4', '#FFF3E8', '#F4845F', '#ff9a5c'];
  const TYPES  = ['circle', 'star', 'note', 'dot'];

  let W, H, particles = [];

  function resize() {
    W = canvas.width  = window.innerWidth;
    H = canvas.height = window.innerHeight;
  }

  function rand(a, b) { return a + Math.random() * (b - a); }

  function make() {
    return {
      x:       rand(0, W),
      y:       rand(0, H),
      size:    rand(4, 13),
      speed:   rand(0.15, 0.48),
      angle:   rand(0, Math.PI * 2),
      drift:   rand(-0.007, 0.007),
      color:   COLORS[Math.floor(Math.random() * COLORS.length)],
      alpha:   rand(0.2, 0.38),
      type:    TYPES[Math.floor(Math.random() * TYPES.length)],
      rot:     rand(0, Math.PI * 2),
      rotSpd:  rand(-0.012, 0.012),
    };
  }

  function drawCircle(p) {
    ctx.beginPath();
    ctx.arc(p.x, p.y, p.size / 2, 0, Math.PI * 2);
    ctx.fill();
  }

  function drawDot(p) {
    ctx.beginPath();
    ctx.arc(p.x, p.y, p.size / 4, 0, Math.PI * 2);
    ctx.fill();
  }

  function drawStar(p) {
    ctx.save();
    ctx.translate(p.x, p.y);
    ctx.rotate(p.rot);
    const r = p.size / 2;
    ctx.beginPath();
    for (let i = 0; i < 4; i++) {
      const a = (i / 4) * Math.PI * 2;
      const b = a + Math.PI / 4;
      ctx.lineTo(Math.cos(a) * r, Math.sin(a) * r);
      ctx.lineTo(Math.cos(b) * r * 0.38, Math.sin(b) * r * 0.38);
    }
    ctx.closePath();
    ctx.fill();
    ctx.restore();
  }

  function drawNote(p) {
    ctx.save();
    ctx.translate(p.x, p.y);
    ctx.rotate(p.rot);
    const s = p.size * 0.65;
    ctx.beginPath();
    ctx.ellipse(-s * 0.1, s * 0.5, s * 0.36, s * 0.26, -0.3, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillRect(s * 0.22, -s * 0.5, s * 0.1, s);
    ctx.restore();
  }

  function tick() {
    ctx.clearRect(0, 0, W, H);
    for (const p of particles) {
      // Move
      p.angle += p.drift;
      p.x += Math.cos(p.angle) * p.speed;
      p.y += Math.sin(p.angle) * p.speed * 0.55 - 0.12;
      p.rot += p.rotSpd;
      // Wrap
      if (p.x < -20) p.x = W + 20;
      if (p.x > W + 20) p.x = -20;
      if (p.y < -20) p.y = H + 20;
      if (p.y > H + 20) p.y = -20;
      // Draw
      ctx.globalAlpha = p.alpha;
      ctx.fillStyle = p.color;
      if      (p.type === 'circle') drawCircle(p);
      else if (p.type === 'star')   drawStar(p);
      else if (p.type === 'note')   drawNote(p);
      else                          drawDot(p);
    }
    ctx.globalAlpha = 1;
    requestAnimationFrame(tick);
  }

  resize();
  const count = window.innerWidth <= 640 ? 25 : 55;
  particles = Array.from({ length: count }, make);
  window.addEventListener('resize', () => {
    resize();
    particles.forEach(p => { if (p.x > W) p.x = rand(0, W); if (p.y > H) p.y = rand(0, H); });
  });
  tick();
})();

/* ══════════════════════════════════════════
   4. MOBILE CARD TAP INTERACTION
   — tap card body  → expand detail panel
   — tap CTA link   → navigate (normal)
   — tap close btn  → collapse
   Only active on touch/mobile breakpoint
══════════════════════════════════════════ */
(function initMobileCards() {
  const cards = document.querySelectorAll('.card');

  function isMobile() { return window.innerWidth <= 640; }

  function openCard(card) {
    cards.forEach(c => { if (c !== card) closeCard(c); });
    card.classList.add('is-open');
    card.setAttribute('aria-expanded', 'true');
    // Scroll card into view smoothly
    setTimeout(() => card.scrollIntoView({ behavior: 'smooth', block: 'nearest' }), 100);
  }

  function closeCard(card) {
    card.classList.remove('is-open');
    card.setAttribute('aria-expanded', 'false');
  }

  cards.forEach(card => {
    // Mobile: tap on card-img-wrap OR card-title-pill = toggle open
    const imgWrap = card.querySelector('.card-img-wrap');
    const pill    = card.querySelector('.card-title-pill');

    [imgWrap, pill].forEach(el => {
      if (!el) return;
      el.addEventListener('click', (e) => {
        if (!isMobile()) return; // Desktop uses CSS hover only
        e.stopPropagation();
        if (card.classList.contains('is-open')) {
          closeCard(card);
        } else {
          openCard(card);
        }
      });
    });

    // Close button
    const closeBtn = card.querySelector('.close-btn');
    if (closeBtn) {
      closeBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        closeCard(card);
      });
    }

    // CTA links: always navigate, stop propagation so card doesn't toggle
    card.querySelectorAll('.cta').forEach(btn => {
      btn.addEventListener('click', (e) => {
        e.stopPropagation(); // prevent card toggle
        // let the <a> href navigate normally
      });
    });

    // Keyboard: Enter/Space toggles (mobile), Escape closes
    card.addEventListener('keydown', (e) => {
      if (!isMobile()) return;
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        card.classList.contains('is-open') ? closeCard(card) : openCard(card);
      }
      if (e.key === 'Escape') closeCard(card);
    });
  });

  // Tap outside = close all (mobile)
  document.addEventListener('click', (e) => {
    if (!isMobile()) return;
    if (!e.target.closest('.card')) cards.forEach(closeCard);
  });
})();
